public interface IIterator<T> {
  bool HasNext();
  T Next();
}

public class NameCollection {
  private readonly List<string> _items = new();
  public void Add(string value) => _items.Add(value);
  public IIterator<string> Iterator() => new NameIterator(_items);
}

public class NameIterator : IIterator<string> {
  private readonly List<string> _items;
  private int _index;
  public NameIterator(List<string> items) { _items = items; }
  public bool HasNext() => _index < _items.Count;
  public string Next() => _items[_index++];
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Iterator_TraversesAllItemsInOrder() {
  var collection = new NameCollection();
  collection.Add("Alice");
  collection.Add("Bob");
  var it = collection.Iterator();
  Assert.AreEqual("Alice", it.Next());
  Assert.AreEqual("Bob", it.Next());
}

[TestMethod]
public void Iterator_HasNextReflectsTraversalState() {
  var collection = new NameCollection();
  collection.Add("Only");
  var it = collection.Iterator();
  Assert.IsTrue(it.HasNext());
  it.Next();
  Assert.IsFalse(it.HasNext());
}
